// FEAT-026 Google Maps Fake Branches classifier
// TODO: Cross-reference lat/lng against official branch CSV when available — for
//       now we flag every non-allowlisted Maps listing for analyst review and
//       escalate based on review sentiment + rating.
const items = $input.all();
const ev = $('Webhook').item.json.body || {};
const headers = ev.headers || {};
const tenantId = headers['x-tenant-id'] || '23610954-5fd0-482f-8eb0-11edce1f5c58';
const taskId = ev.eventData?.actorTaskId || null;
const runId = ev.resource?.id || null;
const datasetId = ev.resource?.defaultDatasetId || null;

const RED_KW = ['fraud', 'fake', 'scam', 'धोखा', 'ಮೋಸ', 'மோசம்'];

function hasRedReview(reviews) {
  if (!Array.isArray(reviews)) return false;
  return reviews.some(r => {
    const t = (r?.text || r?.snippet || '').toLowerCase();
    return RED_KW.some(k => t.includes(k.toLowerCase()));
  });
}

const rows = [];
for (const itm of items) {
  const p = itm.json || {};
  const placeId = p.placeId || p.place_id || p.id || p.url;
  if (!placeId) continue;
  const reviews = p.reviews || p.placeDetails?.reviews || [];
  const red = hasRedReview(reviews);
  const rating = typeof p.totalScore === 'number' ? p.totalScore
               : typeof p.rating === 'number' ? p.rating : null;

  let severity = 'Low';
  if (red) severity = 'Critical';
  else if (rating !== null && rating < 2.0) severity = 'Substantial';
  else if (rating !== null && rating < 3.5) severity = 'Moderate';

  const confidence = red ? 0.85 : 0.6;
  const action = severity === 'Critical' ? 'takedown' : 'monitor';
  const lat = p.location?.lat || p.lat || null;
  const lng = p.location?.lng || p.lng || null;

  rows.push({
    tenant_id: tenantId,
    apify_task_id: taskId,
    apify_run_id: runId,
    apify_dataset_id: datasetId,
    feature_id: 'FEAT-026',
    source: 'apify:google-maps',
    kind: 'fake_branch',
    fraud_pattern: 'fake_branch',
    severity,
    confidence,
    item_id: placeId,
    url_or_value: p.url || placeId,
    evidence: {
      place_id: placeId,
      name: p.title || p.name,
      address: p.address || p.fullAddress,
      phone: p.phone || p.phoneUnformatted,
      rating,
      reviewsCount: p.reviewsCount || p.totalReviews || (reviews?.length || 0),
      lat, lng,
      opening_hours: p.openingHours || p.hours || null,
      top_review_excerpts: reviews.slice(0, 3).map(r => (r?.text || r?.snippet || '').slice(0, 200)),
    },
    language_detected: p.language || null,
    ai_filtered: false,
    ai_reason: red ? 'Reviews mention fraud/scam keywords' :
               rating !== null && rating < 2.0 ? 'Very low rating' :
               rating !== null && rating < 3.5 ? 'Below-average rating' :
               'Listing flagged for analyst review',
    recommended_action: action,
  });
}
return [{ json: { rows, count: rows.length } }];
